svg.script:
var colors = ['#4CAF50', '#2196F3', '#E91E63', '#FF9800', '#9C27B0', '#00BCD4'];
var colorIdx = 0;

function cycleColor() {
  colorIdx = (colorIdx + 1) % colors.length;
  document.getElementById('btn').setAttribute('fill', colors[colorIdx]);
  document.getElementById('btn-shadow').setAttribute('fill', colors[colorIdx]);
}

function resetAll() {
  colorIdx = 0;
  document.getElementById('btn').setAttribute('fill', colors[0]);
  document.getElementById('btn-shadow').setAttribute('fill', colors[0]);
  document.getElementById('counter-text').textContent = 'Clicks: 0';
  clickCount = 0;
}

var clickCount = 0;

window.addEventListener('load', function() {
  // Fade in the whole card on load
  var card = document.getElementById('card');
  card.setAttribute('opacity', '1');

  // Pulse the hint text
  var hint = document.getElementById('hint');
  var visible = true;
  setInterval(function() {
    visible = !visible;
    hint.setAttribute('opacity', visible ? '1' : '0.3');
  }, 800);
});
